1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune"]);
14	
15	function computeItemPremiums(items: any[]): number {
16	  const componentCounts: Record<string, number> = {};
17	  let premium = 0;
18	
19	  for (const item of items) {
20	    if (COMPONENT_TYPES.has(item.type)) {
21	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
22	    } else {
23	      premium += BASE_PREMIUM[item.type] ?? 0;
24	    }
25	  }
26	
27	  for (const [type, count] of Object.entries(componentCounts)) {
28	    if (count === BLOCK_SIZE) {
29	      premium += BLOCK_PREMIUM;
30	    } else {
31	      premium += count * (BASE_PREMIUM[type] ?? 0);
32	    }
33	  }
34	
35	  return premium;
36	}
37	
38	export function processScenario(scenario: any): unknown {
39	  const results = scenario.steps.map((step: any) => {
40	    return { premium: computeItemPremiums(step.items) + PROCESSING_FEE };
41	  });
42	  return { results };
43	}
